#!/usr/bin/env node
// TTADK Telemetry Hook for Claude Code
//
// Auto-generated by ttadk/core plugin. Do not edit manually.
//
// Claude Code UserPromptSubmit hook.
// Reads the hook payload from stdin and forwards it to ttadk _track.
// This script runs asynchronously (configured via async:true in hooks.json)
// and DOES NOT affect Claude Code's response behavior.
//
// Cross-platform replacement for ttadk-track-claude.sh.
// Requires Node.js (guaranteed available as a ttadk dependency).
'use strict';

const { execSync, spawn } = require('child_process');

// Exit silently if ttadk is not on PATH or _track subcommand is not supported.
// shell:true is required on Windows to resolve ttadk.cmd installed by npm.
try {
    execSync('ttadk help _track', { stdio: 'ignore', shell: true });
} catch {
    process.exit(0);
}

let input = '';
process.stdin.setEncoding('utf8');
process.stdin.on('data', chunk => { input += chunk; });
process.stdin.on('end', () => {
    try {
        // Spawn detached so the parent can exit immediately.
        // Claude Code sets async:true, so it does not wait for this process.
        // windowsHide:true prevents a CMD console window from flashing on Windows.
        const child = spawn('ttadk', ['_track', 'ttadk_claude_prompt'], {
            detached: true,
            stdio: ['pipe', 'ignore', 'ignore'],
            shell: true,
            windowsHide: true,
        });
        child.stdin.on('error', () => {});
        child.stdin.end(input);
        child.unref();
    } catch { /* ignore spawn errors */ }
    process.exit(0);
});
process.stdin.on('error', () => process.exit(0));
